#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, X, Y;
        scanf("%d %d %d", &M, &X, &Y);
        int A[M];
        for (int i = 0; i < M; i++) {
            A[i] = i + 1;
        }
        for (int i = 0; i < M / 2 - 1; i++) {
            int mid = M / 2;
            int B[mid], C[mid];
            for (int j = 0; j < mid; j++) {
                B[j] = A[j];
                C[j] = A[j + mid];
            }
            B[X] = 0;
            C[Y] = 0;
            int k = 0;
            for (int j = 0; j < mid; j++) {
                if (B[j] != 0) {
                    A[k++] = B[j];
                }
                if (C[j] != 0) {
                    A[k++] = C[j];
                }
            }
            M = k;
        }
        printf("%d\n", A[0] ^ A[1]);
    }
    return 0;
}

