import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int M = sc.nextInt();
            int X = sc.nextInt();
            int Y = sc.nextInt();
            int[] A = new int[M];
            for (int i = 0; i < M; i++) {
                A[i] = i + 1;
            }
            for (int i = 0; i < M / 2 - 1; i++) {
                int mid = M / 2;
                int[] B = new int[mid];
                int[] C = new int[mid];
                for (int j = 0; j < mid; j++) {
                    B[j] = A[j];
                    C[j] = A[j + mid];
                }
                B[X] = 0;
                C[Y] = 0;
                int k = 0;
                for (int j = 0; j < mid; j++) {
                    if (B[j] != 0) {
                        A[k++] = B[j];
                    }
                    if (C[j] != 0) {
                        A[k++] = C[j];
                    }
                }
                M = k;
            }
            System.out.println(A[0] ^ A[1]);
        }
    }
}

