const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [M, X, Y] = readline().split(' ').map(Number);
    let A = Array.from({ length: M }, (_, i) => i + 1);
    for (let j = 0; j < M / 2 - 1; j++) {
        const mid = M / 2;
        const B = A.slice(0, mid);
        const C = A.slice(mid);
        B[X] = 0;
        C[Y] = 0;
        A = [...B, ...C].filter(x => x !== 0);
        M = A.length;
    }
    console.log(A[0] ^ A[1]);
}
